import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums and processing fee
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote a single plain sword → premium 105 G (100 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 105 }] });
  });
  it("quote a single plain amulet → premium 65 G (60 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 65 }] });
  });
  it("quote a single plain staff → premium 85 G (80 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "oak", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 85 }] });
  });
  it("quote a single plain potion → premium 45 G (40 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 45 }] });
  });

  // Quote: components and building blocks
  it("quote 2 runes → premium 55 G (50 base + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 55 }] });
  });
  it.todo("quote 3 runes → premium 65 G (60 base block + 5 fee)");
  it.todo("quote 4 runes → premium 105 G (100 base + 5 fee)");
  it.todo("quote 2 runes + 1 moonstone → premium 80 G (75 base + 5 fee)");
  it.todo("quote 3 runes + 3 moonstones → premium 125 G (120 base + 5 fee)");

  // Quote: item-specific modifiers
  it.todo("quote a cursed sword → adds 50% surcharge on that item");
  it.todo("quote a highly enchanted sword (enchantment 5) → adds 30% surcharge");
  it.todo("quote a cursed and highly enchanted sword → both surcharges apply");

  // Quote: policy-wide modifiers
  it.todo("quote with long-standing customer (2+ years) → 20% loyalty discount");
  it.todo("quote first contract → 10% first insurance surcharge");
  it.todo("quote follow-up contract → 15% follow-up discount");

  // Quote: integration examples
  it.todo("newcomer with a cursed sword → premium 165 G");
  it.todo("long-standing customer's second contract (cursed enchanted sword) → premium 160 G");

  // Quote: multi-item policy with modifier scope
  it.todo("policy with cursed sword + plain amulet → premium 215 G (210 + 5 fee)");

  // Quote: rounding in MHPCO's favor
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // Claim: basic payout
  it.todo("claim with damage to plain sword (500 G) → payout 400 G (500 - 100 deductible)");
  it.todo("claim with damage to a rune (200 G) → payout 100 G");

  // Claim: special clauses
  it.todo("claim damage to highly enchanted item (level 8) → 50% reimbursement then deductible");
  it.todo("claim damage to dragon-material item → full reimbursement then deductible");
  it.todo("claim dragon-material + enchantment 9 → 50% rule wins");

  // Claim: deductible per damage event
  it.todo("claim with damage to sword and amulet → deductible applies once per damaged item");

  // Claim: cap exhaustion
  it.todo("two successive claims exhaust the 2x insurance cap");

  // Error handling
  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr");
  it.todo("claim referencing item not in policy → CLI exits non-zero");
  it.todo("claim with negative damage amount → CLI exits non-zero");
});

