const PROCESSING_FEE = 5;

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const RUNE_BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

type Item = { type: string };
type Step = { op: string; items: Item[] };
type Scenario = { steps: Step[] };

const basePremiumForItem = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type] ?? 0;

const sumOfIndividualBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumForItem(item), 0);

const countItemsOfType = (items: Item[], type: string): number =>
  items.filter((item) => item.type === type).length;

const basePremiumFor = (items: Item[]): number => {
  if (countItemsOfType(items, "rune") === RUNE_BLOCK_SIZE) return RUNE_BLOCK_PRICE;
  return sumOfIndividualBasePremiums(items);
};

export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
  const { steps } = input as Scenario;
  const premium = basePremiumFor(steps[0].items) + PROCESSING_FEE;
  return { results: [{ premium }] };
};

